import { create } from 'zustand';
export const useModal = create(set => ({
  isOpenAddModel: false,
  isOpenEditModel: false,
  objectToEdit: null,
  setIsOpenAddModel: () => set(state => ({
    isOpenAddModel: !state.isOpenAddModel
  })),
  setIsOpenEditModel: () => set(state => ({
    isOpenEditModel: !state.isOpenEditModel
  })),
  CloseAllModal: () => set(state => ({
    isOpenAddModel: false,
    isOpenEditModel: false
  })),
  SetobjectToEdit: data => set(state => ({
    objectToEdit: data
  }))
}));
